#!/usr/bin/env bash
# Vendored Ghostty / libghostty-vt build for the new architecture.
#
# Builds libghostty-vt into third_party/ghostty/ — the Rust workspace under
# crates/ links the resulting static archive directly via crates/roost-vt's
# build.rs (bindgen + rustc-link-search), and the Mac SwiftPM package under
# mac/ links it via package linker settings (see mac/Package.swift). There is
# no second "build the application" stage here.
#
# This is the single source of the pinned libghostty-vt SHA (the legacy Go
# prototype's build/build.sh was removed in GODELETE).
#
# Usage:
#   ./third_party/ghostty/build.sh           # build (idempotent on cache hit)
#   ./third_party/ghostty/build.sh --force   # discard cache, rebuild from scratch

set -euo pipefail

# --- Pinned versions ---------------------------------------------------------
# Ghostty SHA — bump deliberately, in its own PR, with a rebuild test on
# Linux + Mac CI.
GHOSTTY_SHA="c74f6d56d1feef473033057bc0ff7e3f00cf6421"  # 2026-04-25, builds lib-vt cleanly with zig 0.15.1
GHOSTTY_REPO="https://github.com/ghostty-org/ghostty.git"

# --- Paths -------------------------------------------------------------------
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
GHOSTTY_SRC="${SCRIPT_DIR}/src"
OUT_DIR="${SCRIPT_DIR}/out"

force=0
case "${1:-}" in
  --force) force=1 ;;
  "")      ;;
  *)       echo "usage: $0 [--force]"; exit 1 ;;
esac

if [ "${force}" -eq 1 ]; then
  echo "==> --force: removing ${GHOSTTY_SRC} and ${OUT_DIR}"
  rm -rf "${GHOSTTY_SRC}" "${OUT_DIR}"
fi

command -v zig >/dev/null 2>&1 || {
  echo "error: zig not found on PATH. Run \`mise install\` from the repo root." >&2
  exit 1
}

# Ghostty pins to Zig 0.15.x; both 0.14 and 0.16 produce surprising errors
# downstream. Validate up front so a wrong toolchain is obvious.
zig_version="$(zig version 2>/dev/null || true)"
if ! printf '%s\n' "${zig_version}" | grep -E '^0\.15(\.|$)' >/dev/null; then
  echo "error: zig version ${zig_version:-<unknown>} is not 0.15.x." >&2
  echo "       Install the right toolchain via \`mise install\` from the repo root." >&2
  exit 1
fi

# On macOS 26+ on Apple Silicon, the system libSystem.tbd ships only
# arm64e-macos targets, but Zig 0.15.2 builds its host build runner as
# plain arm64-macos — every libc symbol comes back undefined at link
# time. This shim redirects Zig's SDK lookup to a sibling MacOSX1[45].sdk
# for the duration of the build.
sdk_has_plain_arm64() {
  local tbd="$1/usr/lib/libSystem.tbd"
  [ -f "${tbd}" ] || return 1
  # libSystem.tbd is a multi-document YAML: the first document is the
  # libSystem entry itself; subsequent documents are re-exported
  # sub-libraries that may still list arm64-macos even when libSystem
  # itself is arm64e-only on macOS 26+. Restrict the match to the
  # first document.
  awk '/^---/ && ++n>1 { exit } { print }' "${tbd}" \
    | grep -Eq '(^|[[:space:],])arm64-macos([[:space:],]|$)'
}

maybe_arm64_sdk_shim() {
  [ "$(uname -s)" = "Darwin" ] || return 0
  [ "$(uname -m)" = "arm64" ]  || return 0
  command -v xcrun >/dev/null 2>&1 || return 0

  local default_sdk
  default_sdk="$(xcrun --sdk macosx --show-sdk-path 2>/dev/null || true)"
  [ -n "${default_sdk}" ] || return 0
  if sdk_has_plain_arm64 "${default_sdk}"; then
    return 0
  fi

  local replacement=""
  local candidate
  for candidate in \
    /Library/Developer/CommandLineTools/SDKs/MacOSX15.sdk \
    /Library/Developer/CommandLineTools/SDKs/MacOSX15.4.sdk \
    /Library/Developer/CommandLineTools/SDKs/MacOSX14.sdk \
    /Applications/Xcode.app/Contents/Developer/Platforms/MacOSX.platform/Developer/SDKs/MacOSX15.sdk
  do
    if [ -d "${candidate}" ] && sdk_has_plain_arm64 "${candidate}"; then
      replacement="${candidate}"
      break
    fi
  done

  if [ -z "${replacement}" ]; then
    echo "error: Zig 0.15.2 needs an arm64-macos libSystem.tbd, but the system SDK" >&2
    echo "       at ${default_sdk} only exposes arm64e on this machine," >&2
    echo "       and no sibling MacOSX1[45].sdk with plain arm64 was found." >&2
    echo "       Install Xcode Command Line Tools (which usually ships an older" >&2
    echo "       MacOSX15.sdk alongside the current one), or bump the pinned" >&2
    echo "       Ghostty SHA + Zig version in third_party/ghostty/build.sh." >&2
    exit 1
  fi

  echo "==> macOS 26 SDK lacks arm64-macos in libSystem; redirecting xcrun to ${replacement}"
  local shim_dir
  shim_dir="$(mktemp -d -t roost-xcrun-shim)"
  cat > "${shim_dir}/xcrun" <<EOF
#!/usr/bin/env bash
# Generated by third_party/ghostty/build.sh. Forces Zig's SDK lookup
# to return an arm64-compatible SDK on macOS 26+. All other xcrun
# calls fall through.
for arg in "\$@"; do
  case "\$arg" in
    --show-sdk-path) echo "${replacement}"; exit 0 ;;
  esac
done
exec /usr/bin/xcrun "\$@"
EOF
  chmod +x "${shim_dir}/xcrun"
  export PATH="${shim_dir}:${PATH}"
}

if [ ! -d "${GHOSTTY_SRC}/.git" ]; then
  echo "==> Cloning Ghostty @ ${GHOSTTY_SHA}"
  git clone "${GHOSTTY_REPO}" "${GHOSTTY_SRC}"
fi

pushd "${GHOSTTY_SRC}" >/dev/null
current_sha="$(git rev-parse HEAD)"
if [ "${current_sha}" != "${GHOSTTY_SHA}" ]; then
  echo "==> Checking out ${GHOSTTY_SHA}"
  git fetch --quiet origin "${GHOSTTY_SHA}" || git fetch --quiet
  git checkout --quiet "${GHOSTTY_SHA}"
fi

echo "==> Building libghostty-vt"
maybe_arm64_sdk_shim
# `-Dcpu=baseline`: build for the architecture's portable baseline CPU, not
# the builder's native CPU. Without it, zig (via Ghostty's
# `standardTargetOptions`) bakes in whatever instructions the building
# machine supports — fine locally, but in CI the artifact is cached per-OS
# (not per-CPU) and restored across GitHub's heterogeneous runner fleet, so
# a lib built on a richer CPU SIGILLs (exit -4) the instant it runs on a
# poorer one. That surfaced as a flaky "gtk UI did not boot" + roost-vt ffi
# test crashes. Baseline keeps the static archive portable across any CPU
# of the same arch.
zig build -Demit-lib-vt=true -Doptimize=ReleaseFast -Dcpu=baseline --prefix "${OUT_DIR}"
popd >/dev/null

# zig emits BOTH `libghostty-vt.a` and `libghostty-vt.dylib` (plus
# version-suffixed aliases) into ${OUT_DIR}/lib/. Roost links only
# the static archive — the Swift Mac UI passes it positionally
# (`mac/Package.swift::linkerSettings`); the Rust crates use
# `cargo:rustc-link-arg=<full-path-to-.a>` for the same reason
# (`crates/roost-vt/build.rs`). The dylib is never consumed, but
# leaving it alongside the .a makes macOS `ld` silently prefer
# the dylib on any `-L<dir> -lghostty-vt` form and embed an
# `@rpath/libghostty-vt.dylib` load command that fails at runtime
# (no LC_RPATH is set anywhere). Delete the dylib aliases right
# after the zig step so the only artifact left in lib/ is the
# static archive. The xcframework directory still carries its own
# .a files for iOS / mac-arm64+x86_64 packaging; leave it alone.
echo "==> Removing unused libghostty-vt dylibs"
rm -f "${OUT_DIR}"/lib/libghostty-vt*.dylib

missing_header=0
missing_archive=0
[ -f "${OUT_DIR}/include/ghostty/vt.h" ] || missing_header=1
[ -f "${OUT_DIR}/lib/libghostty-vt.a" ] || missing_archive=1
if [ "${missing_header}" -eq 1 ] || [ "${missing_archive}" -eq 1 ]; then
  echo "error: expected libghostty-vt artifacts not found under ${OUT_DIR} after zig build." >&2
  echo "       missing header (vt.h):                  ${missing_header}" >&2
  echo "       missing static archive (libghostty-vt.a): ${missing_archive}" >&2
  echo "       Inspect ${OUT_DIR} and ${GHOSTTY_SRC}/zig-out/." >&2
  exit 1
fi

echo "==> libghostty-vt built: ${OUT_DIR}"
echo "    header: ${OUT_DIR}/include/ghostty/vt.h"
echo "    static: ${OUT_DIR}/lib/libghostty-vt.a"
